import{_ as e,o as a,c as r,ag as n}from"./chunks/framework.brm5GKsQ.js";const p=JSON.parse('{"title":"Performance","description":"","frontmatter":{},"headers":[],"relativePath":"guide/performance.md","filePath":"guide/performance.md"}'),s={name:"guide/performance.md"};function d(o,t,i,l,h,u){return a(),r("div",null,[...t[0]||(t[0]=[n(`<h1 id="performance" tabindex="-1">Performance <a class="header-anchor" href="#performance" aria-label="Permalink to &quot;Performance&quot;">​</a></h1><p>Flexture and Yoga each win in different scenarios. The right choice depends on your workload.</p><h2 id="performance-profile" tabindex="-1">Performance Profile <a class="header-anchor" href="#performance-profile" aria-label="Permalink to &quot;Performance Profile&quot;">​</a></h2><p>Flexture&#39;s pure JavaScript architecture creates a distinctive performance profile compared to Yoga&#39;s WASM:</p><table tabindex="0"><thead><tr><th>Scenario</th><th>Winner</th><th>Margin</th><th>Why</th></tr></thead><tbody><tr><td><strong>Initial layout</strong> (create + layout)</td><td>Flexture</td><td>1.5-2.5x</td><td>JS node creation is cheap; no WASM boundary crossings</td></tr><tr><td><strong>No-change re-layout</strong></td><td>Flexture</td><td><strong>5.5x</strong></td><td>Fingerprint cache catches unchanged trees at the root</td></tr><tr><td><strong>Incremental re-layout</strong> (single dirty leaf)</td><td>Yoga</td><td>2.8-3.4x</td><td>WASM per-node computation is faster</td></tr><tr><td><strong>Full re-layout</strong> (constraint change on pre-existing tree)</td><td>Yoga</td><td>2.7x</td><td>Same reason -- WASM layout computation is faster</td></tr><tr><td><strong>Deep nesting</strong> (15+ levels)</td><td>Yoga</td><td>increasing</td><td>Flexture&#39;s function call overhead compounds at depth</td></tr></tbody></table><p><strong>Key insight</strong>: Flexture wins at node creation and cache hits. Yoga wins at raw layout computation.</p><h2 id="why-these-trade-offs-exist" tabindex="-1">Why These Trade-offs Exist <a class="header-anchor" href="#why-these-trade-offs-exist" aria-label="Permalink to &quot;Why These Trade-offs Exist&quot;">​</a></h2><h3 id="js-wasm-interop-flexture-s-initial-layout-advantage" tabindex="-1">JS/WASM Interop: Flexture&#39;s Initial Layout Advantage <a class="header-anchor" href="#js-wasm-interop-flexture-s-initial-layout-advantage" aria-label="Permalink to &quot;JS/WASM Interop: Flexture&#39;s Initial Layout Advantage&quot;">​</a></h3><p>Yoga&#39;s WASM module is fast internally, but every interaction crosses the JS/WASM boundary:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>JS                          WASM</span></span>
<span class="line"><span>|                           |</span></span>
<span class="line"><span>+-- node.setWidth(100) -----+-&gt; Write to linear memory</span></span>
<span class="line"><span>+-- node.setFlexGrow(1) ----+-&gt; Write to linear memory</span></span>
<span class="line"><span>+-- node.insertChild() -----+-&gt; Update pointers in memory</span></span>
<span class="line"><span>+-- calculateLayout() ------+-&gt; Run layout algorithm</span></span>
<span class="line"><span>+-- node.getComputedWidth() +-&gt; Read from linear memory</span></span>
<span class="line"><span>|                           |</span></span></code></pre></div><p>Each boundary crossing involves type conversion, memory read/write, and function call overhead. For a 100-node layout, that&#39;s 400+ crossings. This makes Yoga&#39;s node creation ~8x slower than Flexture&#39;s pure-JS creation.</p><h3 id="wasm-computation-yoga-s-re-layout-advantage" tabindex="-1">WASM Computation: Yoga&#39;s Re-layout Advantage <a class="header-anchor" href="#wasm-computation-yoga-s-re-layout-advantage" aria-label="Permalink to &quot;WASM Computation: Yoga&#39;s Re-layout Advantage&quot;">​</a></h3><p>When re-laying out a pre-existing tree, node creation is amortized away. The benchmark becomes pure layout computation, where WASM&#39;s compiled code outperforms JIT-compiled JavaScript.</p><h3 id="fingerprint-cache-flexture-s-no-change-advantage" tabindex="-1">Fingerprint Cache: Flexture&#39;s No-Change Advantage <a class="header-anchor" href="#fingerprint-cache-flexture-s-no-change-advantage" aria-label="Permalink to &quot;Fingerprint Cache: Flexture&#39;s No-Change Advantage&quot;">​</a></h3><p>Flexture stores a 5-field fingerprint per node: <code>(availableWidth, availableHeight, direction, offsetX, offsetY)</code>. When <code>calculateLayout()</code> is called with unchanged constraints on a clean tree, Flexture checks the fingerprint at the root and returns immediately -- <strong>zero tree traversal</strong>.</p><p>This makes Flexture <strong>5.5x faster</strong> for the common case of cursor movement, selection changes, and other UI updates that don&#39;t affect layout.</p><h3 id="zero-allocation-design" tabindex="-1">Zero-Allocation Design <a class="header-anchor" href="#zero-allocation-design" aria-label="Permalink to &quot;Zero-Allocation Design&quot;">​</a></h3><p>The layout algorithm eliminates temporary allocations during layout:</p><ol><li><strong>FlexInfo structs on nodes</strong> -- Mutated in place, not reallocated each pass</li><li><strong>Pre-allocated typed arrays</strong> -- For flex-line tracking</li><li><strong>Inline iteration</strong> -- No <code>filter()</code> calls that allocate intermediate arrays</li></ol><p>See <a href="/flexture/guide/zero-allocation.html">Zero-Allocation Design</a> for implementation details.</p><h2 id="benchmark-results" tabindex="-1">Benchmark Results <a class="header-anchor" href="#benchmark-results" aria-label="Permalink to &quot;Benchmark Results&quot;">​</a></h2><p>All benchmarks on Apple M-series, Bun 1.2, macOS (February 2026), with JIT warmup. Times are mean per operation.</p><h3 id="initial-layout-create-layout" tabindex="-1">Initial Layout (Create + Layout) <a class="header-anchor" href="#initial-layout-create-layout" aria-label="Permalink to &quot;Initial Layout (Create + Layout)&quot;">​</a></h3><h4 id="flat-layouts" tabindex="-1">Flat Layouts <a class="header-anchor" href="#flat-layouts" aria-label="Permalink to &quot;Flat Layouts&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Nodes</th><th>Flexture</th><th>Yoga</th><th>Ratio</th></tr></thead><tbody><tr><td>100</td><td>74 us</td><td>157 us</td><td>Flexture 2.1x</td></tr><tr><td>500</td><td>371 us</td><td>835 us</td><td>Flexture 2.3x</td></tr><tr><td>1000</td><td>767 us</td><td>1797 us</td><td>Flexture 2.3x</td></tr><tr><td>2000</td><td>1497 us</td><td>3937 us</td><td>Flexture 2.6x</td></tr><tr><td>5000</td><td>4929 us</td><td>12496 us</td><td>Flexture 2.5x</td></tr></tbody></table><h4 id="tui-board-columns-x-bordered-cards-with-measure-functions" tabindex="-1">TUI Board (columns x bordered cards with measure functions) <a class="header-anchor" href="#tui-board-columns-x-bordered-cards-with-measure-functions" aria-label="Permalink to &quot;TUI Board (columns x bordered cards with measure functions)&quot;">​</a></h4><p>This mirrors real terminal UI structure: columns with headers, bordered card containers, icon + text rows, text nodes with measure functions.</p><table tabindex="0"><thead><tr><th>Structure</th><th>~Nodes</th><th>Flexture</th><th>Yoga</th><th>Ratio</th></tr></thead><tbody><tr><td>3x5</td><td>64</td><td>124 us</td><td>191 us</td><td>Flexture 1.5x</td></tr><tr><td>5x10</td><td>206</td><td>367 us</td><td>619 us</td><td>Flexture 1.7x</td></tr><tr><td>5x20</td><td>406</td><td>605 us</td><td>1234 us</td><td>Flexture 2.0x</td></tr><tr><td>8x30</td><td>969</td><td>1479 us</td><td>3015 us</td><td>Flexture 2.0x</td></tr></tbody></table><h4 id="deep-nesting" tabindex="-1">Deep Nesting <a class="header-anchor" href="#deep-nesting" aria-label="Permalink to &quot;Deep Nesting&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Depth</th><th>Flexture</th><th>Yoga</th><th>Ratio</th></tr></thead><tbody><tr><td>1</td><td>1.4 us</td><td>3.1 us</td><td>Flexture 2.2x</td></tr><tr><td>5</td><td>7.3 us</td><td>11 us</td><td>Flexture 1.5x</td></tr><tr><td>10</td><td>19 us</td><td>21 us</td><td>Flexture 1.1x</td></tr><tr><td>15</td><td>39 us</td><td>31 us</td><td>Yoga 1.3x</td></tr><tr><td>20</td><td>53 us</td><td>41 us</td><td>Yoga 1.3x</td></tr><tr><td>50</td><td>255 us</td><td>101 us</td><td>Yoga 2.5x</td></tr></tbody></table><p>Flexture wins at shallow nesting but Yoga overtakes at 15+ levels.</p><h3 id="re-layout-pre-existing-tree" tabindex="-1">Re-layout (Pre-existing Tree) <a class="header-anchor" href="#re-layout-pre-existing-tree" aria-label="Permalink to &quot;Re-layout (Pre-existing Tree)&quot;">​</a></h3><h4 id="no-change-re-layout" tabindex="-1">No-Change Re-layout <a class="header-anchor" href="#no-change-re-layout" aria-label="Permalink to &quot;No-Change Re-layout&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Structure</th><th>Flexture</th><th>Yoga</th><th>Ratio</th></tr></thead><tbody><tr><td>5x20 TUI (~406 nodes)</td><td>0.027 us</td><td>0.15 us</td><td><strong>Flexture 5.5x</strong></td></tr><tr><td>8x30 TUI (~969 nodes)</td><td>0.026 us</td><td>0.14 us</td><td><strong>Flexture 5.5x</strong></td></tr></tbody></table><p>Flexture returns in <strong>27 nanoseconds</strong> regardless of tree size -- fingerprint check at root, zero traversal.</p><h4 id="single-leaf-dirty-incremental" tabindex="-1">Single Leaf Dirty (Incremental) <a class="header-anchor" href="#single-leaf-dirty-incremental" aria-label="Permalink to &quot;Single Leaf Dirty (Incremental)&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Structure</th><th>Flexture</th><th>Yoga</th><th>Ratio</th></tr></thead><tbody><tr><td>5x20 TUI (~406 nodes)</td><td>123 us</td><td>37 us</td><td>Yoga 3.4x</td></tr><tr><td>8x30 TUI (~969 nodes)</td><td>244 us</td><td>87 us</td><td>Yoga 2.8x</td></tr></tbody></table><h3 id="feature-specific-benchmarks" tabindex="-1">Feature-Specific Benchmarks <a class="header-anchor" href="#feature-specific-benchmarks" aria-label="Permalink to &quot;Feature-Specific Benchmarks&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Feature</th><th>Winner</th><th>Margin</th></tr></thead><tbody><tr><td>AbsolutePositioning</td><td>Flexture</td><td>3.5x</td></tr><tr><td>FlexShrink</td><td>Flexture</td><td>2.7x</td></tr><tr><td>AlignContent</td><td>Flexture</td><td>2.3x</td></tr><tr><td>FlexGrow</td><td>Flexture</td><td>1.9x</td></tr><tr><td>Gap</td><td>Flexture</td><td>1.5x</td></tr><tr><td>MeasureFunc</td><td>Flexture</td><td>1.4x</td></tr><tr><td>FlexWrap</td><td>Flexture</td><td>1.2x</td></tr><tr><td>PercentValues</td><td>~Equal</td><td>-</td></tr></tbody></table><h2 id="real-world-performance-mix" tabindex="-1">Real-World Performance Mix <a class="header-anchor" href="#real-world-performance-mix" aria-label="Permalink to &quot;Real-World Performance Mix&quot;">​</a></h2><p>For a terminal UI app (the primary target), the operation mix is roughly:</p><table tabindex="0"><thead><tr><th>Operation</th><th>Frequency</th><th>Winner</th></tr></thead><tbody><tr><td>Initial render</td><td>Once</td><td>Flexture 1.5-2x</td></tr><tr><td>Cursor movement (no layout change)</td><td>Very frequent</td><td><strong>Flexture 5.5x</strong></td></tr><tr><td>Content edit (single node dirty)</td><td>Frequent</td><td>Yoga 3x</td></tr><tr><td>Window resize</td><td>Occasional</td><td>Yoga 2.7x</td></tr></tbody></table><p>The no-change case dominates in interactive TUIs. Flexture&#39;s fingerprint cache makes this essentially free.</p><h2 id="running-benchmarks" tabindex="-1">Running Benchmarks <a class="header-anchor" href="#running-benchmarks" aria-label="Permalink to &quot;Running Benchmarks&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Quick comparison (flat + deep, with warmup)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bench</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bench/yoga-compare-warmup.bench.ts</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Real-world scenarios (TUI boards, measure functions, property diversity)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bench</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bench/yoga-compare-rich.bench.ts</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Incremental re-layout (no-change, dirty leaf, resize)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bench</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bench/incremental.bench.ts</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Feature-specific</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bench</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bench/features.bench.ts</span></span></code></pre></div><h2 id="when-to-use-yoga-instead" tabindex="-1">When to Use Yoga Instead <a class="header-anchor" href="#when-to-use-yoga-instead" aria-label="Permalink to &quot;When to Use Yoga Instead&quot;">​</a></h2><ul><li><strong>Frequent incremental re-layout</strong> -- If your primary workload is single-node updates on large pre-existing trees, Yoga&#39;s WASM layout computation is 2-3x faster</li><li><strong>Deep nesting (15+ levels)</strong> -- Yoga&#39;s per-node overhead is lower</li><li><strong>React Native ecosystem</strong> -- Yoga is the native choice</li><li><strong>Cold single-shot layouts</strong> -- No warmup benefit for Flexture</li></ul>`,47)])])}const g=e(s,[["render",d]]);export{p as __pageData,g as default};
